var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 10월 15일 런던, <color=#ffd34c>베이커 가 211번지</color>","JPN":"1888年10月15日　ロンドン、<color=#ffd34c>ベーカー街211番地</color>","ENG":"October 15, 1888, London, <color=#ffd34c>211 Baker St.</color>","TWN":"1888年10月15日 倫敦，<color=#ffd34c>貝克街211號</color>","SCN":"1888年10月15日 伦敦，<color=#ffd34c>贝克街211号</color>","DEU":"October 15, 1888, London, <color=#ffd34c>211 Baker St.</color>","FRA":"October 15, 1888, London, <color=#ffd34c>211 Baker St.</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"도착했네.","JPN":"着いた。","ENG":"We've arrived.","TWN":"到了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"오랜만에 손님이로군. 누추하지만 안으로 들게.","JPN":"久々の客人だな。汚いが、どうぞ入ってくれ。","ENG":"It's been a long time since I had a guest. Please, make yourself at home.","TWN":"好久沒有客人了。雖然簡陋，但請進吧。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"여긴 어디죠?","JPN":"ここはどこですか？","ENG":"Where are we?","TWN":"這是……哪裡？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"내 오랜 아지트 같은 곳이지. 여기라면 일단 쫓길 일은 없을 거야.","JPN":"私の古いアジトのようなところだ。ここならまず追われることはないだろう。","ENG":"It's my old hideout. No one will be on our tail while we're here.","TWN":"這裡是我以前的藏身之處。在這裡暫時不會被追上。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"마도구를 써서 인식을 저해해 두었어. 보통 사람들에게는 평범한 하숙집으로 보이겠지.","JPN":"魔道具を使って認識を阻害しておいた。普通の人間にはそこらの下宿屋に見えるはずだ。","ENG":"I used a Curio to hinder people's perception. To ordinary people, this place will look like a normal boarding home.","TWN":"因為用特殊工具干擾了感知。在普通人看來，這裡只是個普通的寄宿房而已。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"인식을 저해한다고요? 그만한 마도구를 어디서……?","JPN":"認識を阻害する？　そんな魔道具をどこで……？","ENG":"Hinder people's perception? Where did you find a Curio that potent...?","TWN":"干擾感知？那樣的特殊工具是從哪裡……？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 자네보다야 덜 하겠지만 나도 제법 인기가 있는 편이거든.","JPN":"ハハ、君ほどではないが私は結構モテるものでね。","ENG":"Haha, it might not be up to your level, but I'm also rather popular.","TWN":"呵呵，雖然比不上你，但我也算是相當受歡迎的喔。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"물론, 내 목숨을 노리는 범죄자들 한정이지만.","JPN":"もちろん、私の命を狙っている犯罪者限定だが。","ENG":"But only to criminals who want me dead, of course.","TWN":"當然，僅限那些想要我命的罪犯。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그게 자랑할 일이에요?","JPN":"それって、自慢にならないでしょう？","ENG":"I don't think that's something to be proud of.","TWN":"那是值得炫耀的事嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그보다 스완…….","JPN":"それより、スワン……","ENG":"Anyway, Swan...","TWN":"比起這個，史旺……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"벽장 두번째 서랍에 있는 약물과 주사기를 부탁할 수 있을까?","JPN":"クローゼットの二番目の引き出しにある薬物と注射器をお願いできるかね？","ENG":"Could you bring me my medicine and syringe in the second drawer of the closet?","TWN":"能幫我拿一下壁櫥第二層裡的藥物和注射器嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이제 슬슬 한계라서 말이지.","JPN":"もうそろそろ限界だ。","ENG":"I'm at my limit right now.","TWN":"現在差不多到極限了。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"이거 맞죠?","JPN":"これですよね？","ENG":"Is this it?","TWN":"你確定是這個嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 고맙네. 다행히 아직 잔량이 남아있군.","JPN":"そうだ、ありがとう。幸い、まだ残ってるな。","ENG":"Yes. Thank you. Thankfully, there is still some left.","TWN":"是的，謝謝。幸好還有剩餘。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후우우우우…….","JPN":"ふうううう……","ENG":"Phew...","TWN":"呼——"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"대체 그게 뭐죠? 평범한 약물처럼 보이지는 않는데?","JPN":"それ、いったいなんですか？　普通の薬には見えませんけど。","ENG":"What is that? It doesn't look like any ordinary medicine.","TWN":"那到底是什麼？看起來不像是普通的藥物啊？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"마석을 정제하여 순도 높은 각성제와 배합한 <color=#ffd34c>주사액</color>이라네.","JPN":"魔石を精製して高純度の覚醒剤と調合した<color=#ffd34c>注射液</color>だ。","ENG":"It's a <color=#ffd34c>concoction</color> made of refined Mana Stones and high-purity stimulants.","TWN":"那是將魔石精煉後與高純度興奮劑混合製成的<color=#ffd34c>注射液</color>。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"수년 전, 내 오랜 벗이 이곳을 떠나기 전에 만들어 둔 거지.","JPN":"数年前、私の旧友がここを出る前に作っておいたものさ。","ENG":"Years ago, an old friend of mine made it before leaving this place.","TWN":"幾年前，我的一個老友在離開這裡之前製作的。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이게 없으면, 이제 정상적인 생활이 불가능하거든.","JPN":"もうこれがないと、正常な暮らしができなくてね。","ENG":"Without it, I'm unable to function normally now.","TWN":"沒有這個，現在就無法正常生活了。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"뭐라고요……?","JPN":"なんですって……？","ENG":"What...?","TWN":"你說什麼……？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하하, 그럴지도 모르겠군.","JPN":"はは、そうかもしれないな。","ENG":"Haha, perhaps it is.","TWN":"哈哈，也許吧。"},"stage":{"bg":"LONDON_VICTORIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"부디, 무례를 용서해주게. 내게 허락된 시간이 이제 얼마 남지 않았거든.","JPN":"どうか無礼を許してくれたまえ。もう私に残された時間があまりないのだ。","ENG":"But please forgive my rudeness. My time is running out.","TWN":"請原諒我的無禮。但留給我的時間已經不多了。"},"stage":{"bg":"LONDON_VICTORIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};